final:
module gray_code_counter (
        input clk,
        input reset,
        output reg [1:0] gray_count);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        gray_count <= 2'b00;
    else
        case (gray_count)
            2'b00: gray_count <= 2'b01;
            2'b01: gray_count <= 2'b11;
            2'b11: gray_count <= 2'b10;
            2'b10: gray_count <= 2'b00;
            default: gray_count <= 2'b00;
        endcase
end

endmodule
